SELECT track_id
FROM track_streams
WHERE streams = (SELECT MAX(streams) FROM track_streams);

SELECT track_id, SUM(streams) AS total_streams
FROM track_streams
GROUP BY track_id;

SELECT artist_name, genre, bio, created_at
FROM artists
ORDER BY created_at ASC;

SELECT campaign_id, COUNT(track_id) AS track_count
FROM campaign_tracks
GROUP BY campaign_id;
